import { chromium } from 'playwright';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const WORKSPACE_DIR = path.resolve(__dirname, '..');
const COOKIES_FILE = path.join(WORKSPACE_DIR, 'devops_cookies.json');
const PIPELINE_URL = 'https://devops.devcloud.ztgame.com/projects/yyzy/pipelines/p-f78c977835c84b71a6d58b4746cd1c4a';

function log(msg) { console.log(`[DEVOP] ${msg}`); }
async function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

async function main() {
  if (!fs.existsSync(COOKIES_FILE)) { log('❌ Cookie 文件不存在'); process.exit(1); }
  const cookies = JSON.parse(fs.readFileSync(COOKIES_FILE, 'utf8'));
  log(`已加载 ${cookies.length} 个 Cookie`);

  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext({ viewport: { width: 1920, height: 1080 }, locale: 'zh-CN' });
  await context.addCookies(cookies.map(c => ({
    name: c.name, value: c.value, domain: c.domain, path: c.path,
    httpOnly: c.httpOnly || false, secure: c.secure || false, sameSite: c.sameSite || 'Lax',
  })));
  const page = await context.newPage();

  log('打开流水线页面...');
  await page.goto(PIPELINE_URL, { waitUntil: 'networkidle', timeout: 30000 });
  if ((await page.content()).includes('登录') || page.url().includes('login')) {
    log('❌ Cookie 已失效'); await browser.close(); process.exit(1);
  }
  log(`已加载: ${page.url()}`);

  // Click "启动新构建"
  log('点击「启动新构建」...');
  const startBtn = await page.$('button:has-text("启动新构建")');
  if (!startBtn) { log('❌ 未找到按钮'); await browser.close(); process.exit(1); }
  await startBtn.click();
  await sleep(3000);

  // Verify dest is already 1v1_qa
  const destSpan = await page.$('.ant-select-selection-item');
  if (destSpan) {
    const destVal = await destSpan.textContent();
    log(`dest = "${destVal}"`);
  }

  // Click the confirm button - "执 行" (the Ant Design button has space in Chinese chars)
  log('查找「执 行」按钮...');

  // Method 1: Find by text content, normalize spaces
  const allButtons = await page.$$('button');
  let execBtn = null;
  for (const btn of allButtons) {
    const text = ((await btn.textContent()) || '').replace(/\s+/g, ''); // Normalize: remove all whitespace
    if (text === '执行' || text === '确定' || text === '提交' || text === '运行' || text === '确认') {
      execBtn = btn;
      log(`找到按钮: "${await btn.textContent()}" (归一化: "${text}")`);
      break;
    }
  }

  if (!execBtn) {
    // Method 2: Find by class + type
    execBtn = await page.$('button.ant-btn-primary:not(.ant-modal-close)');
    if (execBtn) {
      const txt = await execBtn.textContent();
      log(`找到主按钮: "${txt}"`);
    }
  }

  if (!execBtn) {
    // Method 3: Find by position (the close button is at top-right, exec is in dialog footer)
    const dialog = await page.$('.ant-modal');
    if (dialog) {
      execBtn = await dialog.$('button.ant-btn-primary');
      if (execBtn) {
        const txt = await execBtn.textContent();
        log(`在 dialog 中找到主按钮: "${txt}"`);
      }
    }
  }

  if (execBtn) {
    await execBtn.click();
    log('✅ 已点击执行按钮！');
  } else {
    log('❌ 找不到执行按钮');
    await page.screenshot({ path: path.join(WORKSPACE_DIR, 'devops_no_btn.png'), fullPage: true });
    await browser.close();
    process.exit(1);
  }

  // Wait for build to trigger
  log('等待构建触发...');
  await sleep(5000);

  // Now the dialog should be gone. Reload to see build progress
  await page.goto(PIPELINE_URL, { waitUntil: 'networkidle', timeout: 30000 });
  await sleep(2000);
  log(`构建页面: ${page.url()}`);

  // Monitor build status
  let buildDone = false;
  let result = 'unknown';
  for (let i = 0; i < 40; i++) {
    await sleep(10000);
    log(`检查构建状态 (${i+1}/40)...`);

    const text = await page.evaluate(() => document.body.innerText);

    // Check for success
    if (text.includes('构建成功') || (text.includes('成功') && !text.includes('失败'))) {
      const ok = await page.$('[class*="success"], [class*="passed"], svg[class*="check"]');
      if (ok) { result = 'success'; buildDone = true; log('✅ 构建成功！'); break; }
    }
    if (text.includes('构建失败') || text.includes('失败')) {
      const bad = await page.$('[class*="fail"], [class*="error"], svg[class*="close"]');
      if (bad) { result = 'failed'; buildDone = true; log('❌ 构建失败'); break; }
    }

    log(`  状态: ${text.includes('运行中') ? '运行中' : '等待中'}`);
    await page.reload({ waitUntil: 'networkidle', timeout: 30000 }).catch(() => {});
    await sleep(2000);
  }

  await page.screenshot({ path: path.join(WORKSPACE_DIR, 'devops_final_result.png'), fullPage: true });

  const newCookies = await context.cookies();
  fs.writeFileSync(COOKIES_FILE, JSON.stringify(newCookies, null, 2));
  await browser.close();

  if (result === 'success') { log('✅ 1v1_qa 服构建成功！'); process.exit(0); }
  else if (result === 'failed') { log('❌ 1v1_qa 服构建失败！'); process.exit(1); }
  else { log('⚠️ 构建状态未知，请去 DevOps 页面确认'); process.exit(2); }
}

main().catch(err => { console.error(`[DEVOP] 错误: ${err.message}`); process.exit(1); });

// DevOps Build Trigger Script v3
// Properly closes dropdown before clicking start button
//
// Usage: node devops_trigger_build_v3.mjs <pipelineId> <dest>

import { chromium } from 'playwright';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const WORKSPACE_DIR = path.resolve(__dirname, '..');
const COOKIES_FILE = path.join(WORKSPACE_DIR, 'devops_cookies.json');

const PIPELINE_ID = process.argv[2] || 'p-f78c977835c84b71a6d58b4746cd1c4a';
const DEST = process.argv[3] || '1v1_qa';

function log(msg) {
  console.log(`[${new Date().toISOString()}] ${msg}`);
}

async function main() {
  const cookies = JSON.parse(fs.readFileSync(COOKIES_FILE, 'utf8'));
  log(`Loaded ${cookies.length} cookies`);

  const browser = await chromium.launch({
    headless: true,
    args: ['--no-sandbox', '--disable-blink-features=AutomationControlled'],
  });
  const ctx = await browser.newContext({
    locale: 'zh-CN',
    viewport: { width: 1920, height: 1080 },
    ignoreHTTPSErrors: true,
  });
  await ctx.addCookies(cookies);
  const page = await ctx.newPage();

  // Track API responses for build trigger confirmation
  let triggeredBuildId = null;
  page.on('response', async (resp) => {
    const url = resp.url();
    if (resp.request().method() === 'POST' && (url.includes('/builds') || url.includes('/build'))) {
      try {
        const body = await resp.text().catch(() => '');
        log(`Build API [${resp.status()}] ${url.substring(0, 120)}: ${body.substring(0, 300)}`);
        const match = body.match(/"data"\s*:\s*"(b-[a-z0-9]+)"/);
        if (match) triggeredBuildId = match[1];
      } catch {}
    }
  });

  try {
    const pipelineUrl = `https://devops.devcloud.ztgame.com/projects/yyzy/pipelines/${PIPELINE_ID}`;
    log(`Opening: ${pipelineUrl}`);
    await page.goto(pipelineUrl, { waitUntil: 'networkidle', timeout: 40000 });
    await page.waitForTimeout(2000);

    const pageUrl = page.url();
    if (pageUrl.includes('login')) {
      log('❌ Session expired');
      process.exit(1);
    }

    // Click "启动新构建"
    log('Clicking 启动新构建...');
    await page.click('button:has-text("启动新构建")');
    await page.waitForTimeout(3000);

    // Verify dialog appeared
    const selects = await page.locator('.ant-select').count();
    log(`Dialog selects count: ${selects}`);

    if (selects === 0) {
      log('Dialog may not have appeared');
    }

    // Get current value of first select (dest)
    const destCurrentValue = await page.evaluate(() => {
      const firstSelect = document.querySelector('.ant-select');
      return firstSelect ? firstSelect.innerText.trim() : 'not found';
    });
    log(`Dest current value: ${destCurrentValue}`);

    if (destCurrentValue === DEST) {
      log(`✅ dest already set to ${DEST}, no change needed`);
    } else {
      // Need to change the dest value
      log(`Changing dest from "${destCurrentValue}" to "${DEST}"...`);

      // Click the first select to open dropdown
      const firstSelect = page.locator('.ant-select').first();
      await firstSelect.click();
      await page.waitForTimeout(1000);

      // Wait for dropdown to appear
      await page.waitForSelector('.ant-select-dropdown', { timeout: 5000 }).catch(() => {
        log('Dropdown not appeared via .ant-select-dropdown');
      });

      // Find and click the option
      const optionLocator = page.locator(`.ant-select-item:has-text("${DEST}"), .ant-select-dropdown li:has-text("${DEST}")`).first();
      const optionCount = await optionLocator.count();
      log(`Options for ${DEST}: ${optionCount}`);

      if (optionCount > 0) {
        await optionLocator.click();
        log(`✅ Selected ${DEST}`);
      } else {
        // List all options
        const allOptions = await page.evaluate(() => {
          const opts = document.querySelectorAll('.ant-select-item, .ant-select-item-option');
          return Array.from(opts).map(o => o.innerText || o.title).filter(Boolean);
        });
        log(`Available options: ${JSON.stringify(allOptions)}`);

        if (allOptions.length > 0) {
          // Try to find close match
          const match = allOptions.find(o => o.includes(DEST) || DEST.includes(o));
          if (match) {
            await page.click(`.ant-select-item:has-text("${match}")`);
            log(`✅ Selected closest match: ${match}`);
          } else {
            log(`⚠️ Could not find ${DEST} in options`);
          }
        }
      }
    }

    // Press Escape to close any open dropdown, then wait
    await page.keyboard.press('Escape');
    await page.waitForTimeout(1000);

    // Take screenshot to verify state
    await page.screenshot({ path: path.join(WORKSPACE_DIR, 'memory', 'devops_v3_before_start.png') });
    log('Screenshot: devops_v3_before_start.png');

    // Now click the "启动" button using JavaScript to avoid overlay issues
    log('Clicking 启动 button via JavaScript...');
    const clicked = await page.evaluate(() => {
      // Find the primary button in the modal footer
      const modalFooter = document.querySelector('.ant-modal-footer, .ant-modal-content');
      if (!modalFooter) return { success: false, reason: 'no modal footer' };

      const buttons = Array.from(modalFooter.querySelectorAll('button'));
      const startBtn = buttons.find(b => b.innerText.includes('启动') && !b.innerText.includes('新构建'));

      if (startBtn) {
        startBtn.click();
        return { success: true, text: startBtn.innerText };
      }

      // Try any primary button
      const primaryBtn = buttons.find(b => b.className.includes('primary'));
      if (primaryBtn) {
        primaryBtn.click();
        return { success: true, text: primaryBtn.innerText, type: 'primary' };
      }

      return { success: false, reason: `buttons found: ${buttons.map(b => b.innerText).join(', ')}` };
    });
    log(`JS click result: ${JSON.stringify(clicked)}`);

    await page.waitForTimeout(5000);
    await page.screenshot({ path: path.join(WORKSPACE_DIR, 'memory', 'devops_v3_after_start.png') });

    // Check result
    const finalUrl = page.url();
    const finalText = await page.evaluate(() => document.body.innerText.substring(0, 1500));
    log(`Final URL: ${finalUrl}`);
    log(`Final text: ${finalText.substring(0, 400)}`);

    // Check for success indicators
    const buildIdInUrl = finalUrl.match(/buildId=(b-[a-z0-9]+)/);
    const buildNumInText = finalText.match(/#(\d+)/g);

    if (buildIdInUrl) triggeredBuildId = buildIdInUrl[1];

    // Save refreshed cookies
    const newCookies = await ctx.cookies();
    fs.writeFileSync(COOKIES_FILE, JSON.stringify(newCookies, null, 2));
    log(`Saved ${newCookies.length} cookies`);

    if (triggeredBuildId || (clicked.success && buildNumInText)) {
      log(`✅ SUCCESS! Build triggered. ID: ${triggeredBuildId || 'unknown'}, Build: ${buildNumInText ? buildNumInText[0] : 'unknown'}`);
      await browser.close();
      process.exit(0);
    } else {
      log(`⚠️ Uncertain result. clicked=${JSON.stringify(clicked)}`);
      await browser.close();
      process.exit(1);
    }

  } catch (e) {
    log(`ERROR: ${e.message}`);
    try {
      await page.screenshot({ path: path.join(WORKSPACE_DIR, 'memory', 'devops_v3_error.png') });
    } catch {}
    try { await browser.close(); } catch {}
    process.exit(2);
  }
}

main();

// DevOps Build Status Poller v3
// Captures build status from network API calls on the main pipeline page
//
// Usage: node devops_poll_v3.mjs <pipelineId> <buildId>

import { chromium } from 'playwright';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const WORKSPACE_DIR = path.resolve(__dirname, '..');
const COOKIES_FILE = path.join(WORKSPACE_DIR, 'devops_cookies.json');

const PIPELINE_ID = process.argv[2] || 'p-f78c977835c84b71a6d58b4746cd1c4a';
const BUILD_ID = process.argv[3] || '';
const MAX_WAIT_MINUTES = parseInt(process.argv[4] || '25');

function log(msg) {
  console.log(`[${new Date().toISOString()}] ${msg}`);
}

const SUCCESS_STATUSES = ['succeed', 'success'];
const FAIL_STATUSES = ['failed', 'failure', 'canceled', 'terminate', 'heartbeat_timeout'];

async function checkBuildOnce(cookies) {
  const browser = await chromium.launch({
    headless: true,
    args: ['--no-sandbox'],
  });
  const ctx = await browser.newContext({
    locale: 'zh-CN',
    viewport: { width: 1920, height: 1080 },
    ignoreHTTPSErrors: true,
  });
  await ctx.addCookies(cookies);
  const page = await ctx.newPage();

  let buildStatus = null;
  let buildResult = null;
  const capturedApis = [];

  page.on('response', async (resp) => {
    const url = resp.url();
    // Capture ALL API responses to learn the API structure
    if (url.includes('/ms/') || url.includes('/api/')) {
      try {
        const body = await resp.text().catch(() => '');
        if (body.length > 5 && body.length < 20000 && body.includes('{')) {
          capturedApis.push({ url: url.substring(0, 150), status: resp.status(), body: body.substring(0, 500) });

          // Try to parse and find build status
          try {
            const data = JSON.parse(body);
            const checkObj = (obj, depth = 0) => {
              if (!obj || typeof obj !== 'object' || depth > 5) return;

              // Check for build ID reference
              const str = JSON.stringify(obj).toLowerCase();
              if (str.includes(BUILD_ID.toLowerCase()) || str.includes('b-f5c3bf')) {
                log(`Found build reference in: ${url.substring(0, 80)}`);
                log(`  Data: ${JSON.stringify(obj).substring(0, 300)}`);

                const s = obj.status || obj.buildStatus || obj.buildStatusDesc;
                const r = obj.result || obj.buildResult;
                if (s && !buildStatus) buildStatus = String(s);
                if (r && !buildResult) buildResult = String(r);
              }
            };

            checkObj(data);
            if (data.data) checkObj(data.data);
            if (Array.isArray(data.data)) data.data.forEach(item => checkObj(item));
          } catch {}
        }
      } catch {}
    }
  });

  try {
    // Use the URL with buildId query param that worked before
    const buildUrl = `https://devops.devcloud.ztgame.com/projects/yyzy/pipelines/${PIPELINE_ID}?buildId=${BUILD_ID}`;
    log(`Navigating to: ${buildUrl}`);
    await page.goto(buildUrl, { waitUntil: 'networkidle', timeout: 40000 });
    await page.waitForTimeout(5000);

    const currentUrl = page.url();
    const pageText = await page.evaluate(() => document.body.innerText.substring(0, 3000));
    log(`URL: ${currentUrl}`);
    log(`Page (first 500): ${pageText.substring(0, 500)}`);

    // Log all captured APIs
    log(`\nCaptured ${capturedApis.length} API calls:`);
    capturedApis.slice(0, 15).forEach(a => {
      log(`  [${a.status}] ${a.url}`);
    });

    // Try to find status from page content
    if (!buildStatus) {
      // Look for status indicators in the page
      const statusMap = {
        '运行中': 'RUNNING',
        'Running': 'RUNNING', 
        '排队中': 'QUEUE',
        '成功': 'SUCCEED',
        '失败': 'FAILED',
        '已取消': 'CANCELED',
      };

      for (const [text, status] of Object.entries(statusMap)) {
        if (pageText.includes(text)) {
          buildStatus = status;
          log(`Found status from page text: ${text} → ${status}`);
          break;
        }
      }
    }

    // Check for specific build detail on page
    // The page shows build history - look for #1086 status
    const buildNumMatch = pageText.match(/#1086[\s\S]{0,200}/);
    if (buildNumMatch) {
      log(`Build #1086 context: ${buildNumMatch[0].substring(0, 200)}`);
    }

    // Try to find the actual build status from network responses by trying the API directly
    const devopsToken = cookies.find(c => c.name === 'devops_token')?.value;
    if (devopsToken) {
      log('\nTrying direct API with token...');
      const resp = await fetch(`https://devops.devcloud.ztgame.com/ms/process/api/user/builds/yyzy/${PIPELINE_ID}/${BUILD_ID}`, {
        headers: {
          'Cookie': `devops_token=${devopsToken}`,
          'Accept': 'application/json',
          'X-DEVOPS-PROJECT-ID': 'yyzy',
        }
      });
      const body = await resp.text();
      log(`Direct API [${resp.status}]: ${body.substring(0, 500)}`);

      if (resp.status === 200) {
        try {
          const data = JSON.parse(body);
          const s = data?.data?.status || data?.data?.buildStatus;
          if (s) buildStatus = s;
          log(`API status: ${s}`);
        } catch {}
      }
    }

  } catch (e) {
    log(`Error: ${e.message}`);
  } finally {
    const newCookies = await ctx.cookies();
    fs.writeFileSync(COOKIES_FILE, JSON.stringify(newCookies, null, 2));
    await browser.close();
  }

  return { status: buildStatus, result: buildResult };
}

async function main() {
  const cookies = JSON.parse(fs.readFileSync(COOKIES_FILE, 'utf8'));
  log(`Polling build ${BUILD_ID}`);

  const startTime = Date.now();
  const maxMs = MAX_WAIT_MINUTES * 60 * 1000;
  let attempt = 0;

  while (Date.now() - startTime < maxMs) {
    attempt++;
    log(`\n=== Poll #${attempt} ===`);

    const freshCookies = JSON.parse(fs.readFileSync(COOKIES_FILE, 'utf8'));
    const { status, result } = await checkBuildOnce(freshCookies);

    log(`\nResult: status=${status || 'unknown'}, result=${result || 'unknown'}`);

    const checkStr = `${status || ''} ${result || ''}`.toLowerCase();

    if (SUCCESS_STATUSES.some(s => checkStr.includes(s))) {
      log('✅ BUILD SUCCEEDED!');
      console.log('FINAL_STATUS:SUCCESS');
      process.exit(0);
    }

    if (FAIL_STATUSES.some(s => checkStr.includes(s))) {
      log('❌ BUILD FAILED!');
      console.log('FINAL_STATUS:FAILED');
      process.exit(1);
    }

    if (attempt === 1) {
      // On first poll, just learn the API structure; don't wait too long
      log('First poll complete. Waiting 60s before next check...');
      await new Promise(r => setTimeout(r, 60000));
    } else {
      log('Waiting 60s...');
      await new Promise(r => setTimeout(r, 60000));
    }
  }

  log('TIMEOUT');
  console.log('FINAL_STATUS:TIMEOUT');
  process.exit(2);
}

main();

