// DevOps 1v1_test 服务器更新脚本
// 打开流水线页面 → 选择 dest=1v1_test → 触发构建 → 等待构建完成

import { chromium } from 'playwright';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const WORKSPACE_DIR = path.resolve(__dirname, '..');
const COOKIES_FILE = path.join(WORKSPACE_DIR, 'devops_cookies.json');
const PIPELINE_ID = 'p-f78c977835c84b71a6d58b4746cd1c4a';

function log(msg) { console.log(`[DEVOP] ${msg}`); }
async function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

async function main() {
  // 1. Load cookies
  if (!fs.existsSync(COOKIES_FILE)) { log('❌ Cookie 文件不存在'); process.exit(1); }
  const cookies = JSON.parse(fs.readFileSync(COOKIES_FILE, 'utf8'));
  log(`已加载 ${cookies.length} 个 Cookie`);

  const browser = await chromium.launch({ headless: true, args: ['--no-sandbox'] });
  const context = await browser.newContext({
    viewport: { width: 1920, height: 1080 },
    locale: 'zh-CN',
    ignoreHTTPSErrors: true,
  });
  await context.addCookies(cookies.map(c => ({
    name: c.name, value: c.value, domain: c.domain, path: c.path,
    httpOnly: c.httpOnly || false, secure: c.secure || false, sameSite: c.sameSite || 'Lax',
  })));
  const page = await context.newPage();

  // 2. Open pipeline page
  const pipelineUrl = `https://devops.devcloud.ztgame.com/projects/yyzy/pipelines/${PIPELINE_ID}`;
  log(`打开流水线页面: ${pipelineUrl}`);
  await page.goto(pipelineUrl, { waitUntil: 'networkidle', timeout: 40000 });

  if (page.url().includes('login')) {
    log('❌ Cookie 已失效，需要重新登录');
    await browser.close();
    process.exit(1);
  }
  log(`已加载: ${page.url()}`);

  // 3. Click "启动新构建"
  log('点击「启动新构建」...');
  await page.click('button:has-text("启动新构建")');
  await sleep(3000);

  // 4. Change dest to 1v1_test
  log('更改 dest 为 1v1_test...');

  // Get current value
  const currentDest = await page.evaluate(() => {
    const firstSelect = document.querySelector('.ant-select');
    return firstSelect ? firstSelect.innerText.trim() : 'not found';
  });
  log(`当前 dest: "${currentDest}"`);

  if (currentDest === '1v1_test') {
    log('✅ dest 已经是 1v1_test，无需修改');
  } else {
    // Open the dropdown
    const firstSelect = page.locator('.ant-select').first();
    await firstSelect.click();
    await sleep(1500);

    // Try to find and click the 1v1_test option
    const option = page.locator(`.ant-select-item:has-text("1v1_test"), .ant-select-item-option:has-text("1v1_test")`).first();
    const optionCount = await option.count();

    if (optionCount > 0) {
      await option.click();
      log('✅ 已选择 1v1_test');
      await sleep(1000);
    } else {
      // List all options for debugging
      const allOptions = await page.evaluate(() => {
        const opts = document.querySelectorAll('.ant-select-item, .ant-select-item-option');
        return Array.from(opts).map(o => o.innerText || o.title).filter(Boolean);
      });
      log(`可用选项: ${JSON.stringify(allOptions)}`);

      // Try to find a match
      const match = allOptions.find(o => o.trim() === '1v1_test');
      if (match) {
        await page.click(`.ant-select-item:has-text("1v1_test")`);
        log('✅ 已选择 1v1_test');
        await sleep(1000);
      } else {
        log('⚠️ 未找到 1v1_test 选项，将使用当前 dest');
      }
    }
  }

  // Close any open dropdown
  await page.keyboard.press('Escape');
  await sleep(1000);

  // 5. Click the Execute/启动 button
  log('查找「启动」按钮...');

  // Method 1: Try clicking the primary button via JavaScript
  const clicked = await page.evaluate(() => {
    const modal = document.querySelector('.ant-modal');
    if (!modal) return { success: false, reason: 'no modal' };
    const footer = modal.querySelector('.ant-modal-footer');
    if (!footer) return { success: false, reason: 'no footer' };
    const buttons = Array.from(footer.querySelectorAll('button'));
    const startBtn = buttons.find(b => b.innerText.replace(/\s/g, '') === '启动');
    if (startBtn) { startBtn.click(); return { success: true, text: startBtn.innerText }; }
    const primaryBtn = buttons.find(b => b.className.includes('primary'));
    if (primaryBtn) { primaryBtn.click(); return { success: true, text: primaryBtn.innerText }; }
    return { success: false, reason: `buttons: ${buttons.map(b => b.innerText).join(', ')}` };
  });
  log(`点击结果: ${JSON.stringify(clicked)}`);

  if (!clicked.success) {
    // Fallback: try clicking any button that contains 启动 (without 新构建)
    try {
      const btn = page.locator('button:has-text("启动"):not(:has-text("新构建"))').first();
      if (await btn.count() > 0) {
        await btn.click();
        log('✅ 通过文字匹配点击了启动按钮');
      }
    } catch(e) {
      log(`❌ 无法点击启动按钮: ${e.message}`);
      await page.screenshot({ path: path.join(WORKSPACE_DIR, 'memory', 'devops_error_no_btn.png'), fullPage: true });
      await browser.close();
      process.exit(1);
    }
  }

  // Wait for trigger
  log('等待构建触发...');
  await sleep(8000);

  // Take screenshot after trigger
  await page.screenshot({ path: path.join(WORKSPACE_DIR, 'memory', 'devops_after_start.png') });

  // 6. Reload to see build progress
  await page.goto(pipelineUrl, { waitUntil: 'networkidle', timeout: 40000 }).catch(() => {});
  await sleep(3000);

  // 7. Monitor build status
  log('开始监控构建状态（最多等待 30 分钟）...');
  let buildDone = false;
  let result = 'unknown';
  let maxChecks = 120; // 120 * 15s = 30 min

  for (let i = 0; i < maxChecks; i++) {
    await sleep(15000);
    const text = await page.evaluate(() => document.body.innerText);
    const elapsed = Math.floor((i + 1) * 15 / 60);
    log(`检查构建状态 #${i+1} (已过 ${elapsed} 分钟)...`);

    // Check for success indicators
    if (text.includes('构建成功')) {
      result = 'success';
      buildDone = true;
      log('✅ 构建成功！');
      break;
    }
    if (text.includes('构建失败')) {
      result = 'failed';
      buildDone = true;
      log('❌ 构建失败');
      break;
    }
    if (text.includes('失败') && !text.includes('运行中')) {
      // Check if failure is about a specific build
      const failBadge = await page.$('[class*="fail"], [class*="error"], [class*="red"]');
      if (failBadge) {
        const failParent = await page.evaluate(el => el.closest('[class*="build"]')?.innerText, failBadge);
        if (failParent) {
          result = 'failed';
          buildDone = true;
          log('❌ 构建失败');
          break;
        }
      }
    }

    const running = text.includes('运行中');
    log(`  页面状态: ${running ? '运行中' : '等待中/未知'}`);

    await page.reload({ waitUntil: 'networkidle', timeout: 30000 }).catch(() => {});
    await sleep(2000);
  }

  // Save final screenshot
  await page.screenshot({ path: path.join(WORKSPACE_DIR, 'memory', 'devops_final_result.png'), fullPage: true });

  // Refresh cookies
  const newCookies = await context.cookies();
  fs.writeFileSync(COOKIES_FILE, JSON.stringify(newCookies, null, 2));
  await browser.close();

  // Output result
  if (result === 'success') {
    log('✅ 1v1_test 服构建成功！');
    process.exit(0);
  } else if (result === 'failed') {
    log('❌ 1v1_test 服构建失败！');
    process.exit(1);
  } else {
    log('⚠️ 构建状态未知，请前往 DevOps 页面确认');
    process.exit(2);
  }
}

main().catch(err => {
  console.error(`[DEVOP] 错误: ${err.message}`);
  process.exit(1);
});

