// 打开 DevOps 页面，如果需要登录则走 Keycloak 流程，保存新 Cookie

import { chromium } from 'playwright';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const WORKSPACE_DIR = path.resolve(__dirname, '..');
const COOKIES_FILE = path.join(WORKSPACE_DIR, 'devops_cookies.json');
const PIPELINE_URL = 'https://devops.devcloud.ztgame.com/projects/yyzy/pipelines/p-f78c977835c84b71a6d58b4746cd1c4a';

function log(msg) { console.log(`[DEVOP] ${msg}`); }
async function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

async function main() {
  log('=== DevOps 重新登录 ===');

  // Load any existing cookies (may include Feishu cookies)
  let cookies = [];
  if (fs.existsSync(COOKIES_FILE)) {
    cookies = JSON.parse(fs.readFileSync(COOKIES_FILE, 'utf8'));
    log(`已加载 ${cookies.length} 个现有 Cookie`);
  }

  const browser = await chromium.launch({
    headless: false,  // Use headed mode for login interaction
    args: ['--no-sandbox', '--disable-blink-features=AutomationControlled'],
  });
  const ctx = await browser.newContext({
    viewport: { width: 1920, height: 1080 },
    locale: 'zh-CN',
    ignoreHTTPSErrors: true,
  });

  // Add existing cookies (including Feishu cookies which might help with SSO)
  if (cookies.length > 0) {
    await ctx.addCookies(cookies.map(c => ({
      name: c.name, value: c.value, domain: c.domain, path: c.path,
      httpOnly: c.httpOnly || false, secure: c.secure || false, sameSite: c.sameSite || 'Lax',
    })));
  }

  const page = await ctx.newPage();

  log(`打开 DevOps: ${PIPELINE_URL}`);
  await page.goto(PIPELINE_URL, { waitUntil: 'networkidle', timeout: 30000 });
  await sleep(3000);

  const currentUrl = page.url();
  log(`当前 URL: ${currentUrl}`);

  if (currentUrl.includes('login') || currentUrl.includes('auth')) {
    log('需要登录，尝试自动登录...');
    // Take a screenshot of the login page for reference
    await page.screenshot({ path: path.join(WORKSPACE_DIR, 'memory', 'devops_login_page.png'), fullPage: true });

    // Try to find and click the Feishu SSO login button
    const ssoButtons = await page.$$('button:has-text("飞书"), button:has-text("Feishu"), a:has-text("飞书"), a:has-text("Feishu")');
    log(`找到 ${ssoButtons.length} 个 Feishu SSO 按钮`);

    for (const btn of ssoButtons) {
      const text = await btn.textContent();
      log(`  SSO 按钮: "${text}"`);
    }

    if (ssoButtons.length > 0) {
      log('点击飞书 SSO 登录...');
      await ssoButtons[0].click();
      await sleep(5000);

      const afterSsoUrl = page.url();
      log(`SSO 后 URL: ${afterSsoUrl}`);

      // If it redirected back to DevOps, we're logged in
      if (afterSsoUrl.includes('devops.devcloud.ztgame.com') && !afterSsoUrl.includes('login')) {
        log('✅ Feishu SSO 登录成功！');
      } else {
        log('等待 Feishu SSO 完成...');
        await page.waitForTimeout(10000);
        const finalUrl = page.url();
        log(`最终 URL: ${finalUrl}`);

        if (finalUrl.includes('devops.devcloud.ztgame.com') && !finalUrl.includes('login')) {
          log('✅ Feishu SSO 登录成功！');
        } else {
          log('⚠️ Feishu SSO 未自动完成，请在浏览器中手动完成登录，之后按回车键继续...');
          // Wait for user interaction
          await page.waitForTimeout(60000); // Wait 1 minute for manual login
        }
      }
    } else {
      // Also check for the Keycloak login page
      log('未找到 SSO 按钮，检查 Keycloak 登录页面...');
      await page.screenshot({ path: path.join(WORKSPACE_DIR, 'memory', 'devops_keycloak_page.png'), fullPage: true });

      // Try to find any login buttons
      const allButtons = await page.evaluate(() => {
        return Array.from(document.querySelectorAll('button, a, input[type="submit"]'))
          .map(el => ({
            tag: el.tagName,
            text: el.innerText || el.value || '',
            type: el.type || '',
            href: el.href || '',
          }))
          .filter(b => b.text.includes('登录') || b.text.includes('飞书') || b.text.includes('Feishu') || b.type === 'submit');
      });
      log(`找到的登录元素: ${JSON.stringify(allButtons, null, 2)}`);

      log('请在浏览器中手动完成 DevOps 登录，之后按回车键继续...');
      log('等待最多 2 分钟...');
      await page.waitForTimeout(120000); // Wait 2 minutes
    }
  }

  // Save the new cookies
  await sleep(2000);
  const finalUrl = page.url();
  log(`最终 URL: ${finalUrl}`);

  const newCookies = await ctx.cookies();
  fs.writeFileSync(COOKIES_FILE, JSON.stringify(newCookies, null, 2));
  log(`已保存 ${newCookies.length} 个 Cookie`);

  await browser.close();

  if (finalUrl.includes('devops.devcloud.ztgame.com') && !finalUrl.includes('login')) {
    log('✅ DevOps 登录成功，Cookie 已更新！');
    process.exit(0);
  } else {
    log('❌ DevOps 登录未完成');
    process.exit(1);
  }
}

main().catch(err => {
  console.error(`错误: ${err.message}`);
  process.exit(1);
});

